ForEach:
DECLARE cursor_name CURSOR FOR SELECT col FROM table;
OPEN cursor_name;
FETCH NEXT FROM cursor_name INTO @item;
WHILE @@FETCH_STATUS = 0
BEGIN
    -- body
    FETCH NEXT FROM cursor_name INTO @item;
END

ForLoop:
DECLARE @i INT = 0;
WHILE @i < 10
BEGIN
    -- body
    SET @i = @i + 1;
END

TryCatch:
BEGIN TRY
    EXEC do_something;
END TRY
BEGIN CATCH
    EXEC handle_error;
END CATCH

ProcedureDefinition:
declare function local:log-message(
    $msg as xs:string
) as empty-sequence() {
    (); (: side effects in XQuery are implementation-defined or via extensions :)
};

FunctionDefinition:
declare function local:add(
    $a as xs:integer,
    $b as xs:integer
) as xs:integer {
    $a + $b
};
